data.content:
MSTest **does not have** `Assert.IsGreaterThan` or `Assert.IsInRange` — those don't exist. For numeric boundary checks, use:

- **`Assert.IsTrue(value > threshold)`** — works but gives poor failure messages
- **`Assert.AreEqual(expected, actual)`** — for exact values
- **`Assert.ThrowsException<T>()`** — for invalid input boundaries

Here's a complete test class:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calculator = new();

    // --- CalculatePercentage ---

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calculator.CalculatePercentage(10, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroCorrect_Returns0()
    {
        Assert.AreEqual(0.0, _calculator.CalculatePercentage(0, 10));
    }

    [TestMethod]
    public void CalculatePercentage_PartialScore_ReturnsExpected()
    {
        Assert.AreEqual(75.0, _calculator.CalculatePercentage(3, 4));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(0, 0));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculatePercentage(11, 10));
    }

    // --- GetGrade boundaries ---

    [DataTestMethod]
    [DataRow(100.0, "A")]
    [DataRow(90.0,  "A")]  // boundary: exactly 90
    [DataRow(89.99, "B")]  // just below A
    [DataRow(80.0,  "B")]
    [DataRow(79.99, "C")]
    [DataRow(70.0,  "C")]
    [DataRow(69.99, "D")]
    [DataRow(60.0,  "D")]
    [DataRow(59.99, "F")]
    [DataRow(0.0,   "F")]
    public void GetGrade_AtBoundaries_ReturnsCorrectGrade(
        double percentage, string expectedGrade)
    {
        Assert.AreEqual(expectedGrade, _calculator.GetGrade(percentage));
    }

    // --- NormalizeScore ---

    [TestMethod]
    public void NormalizeScore_ResultIsBetween0And100()
    {
        double result = _calculator.NormalizeScore(45, 50);

        // MSTest has no IsInRange — use IsTrue with a descriptive message
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_ClampedTo100()
    {
        Assert.AreEqual(100.0, _calculator.NormalizeScore(150, 100));
    }

    [TestMethod]
    public void NormalizeScore_NegativeRaw_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(-1, 100));
    }

    [TestMethod]
    public void NormalizeScore_ZeroMax_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.NormalizeScore(50, 0));
    }
}
```

**Key takeaways:**

| Need | MSTest approach |
|---|---|
| Exact value | `Assert.AreEqual(expected, actual)` |
| Range/comparison | `Assert.IsTrue(val > x, "message")` — always add a message for useful failures |
| Exception boundary | `Assert.ThrowsException<T>()` |
| Many boundaries | `[DataTestMethod]` + `[DataRow]` |

If you want richer assertions (`.Should().BeInRange()`, `.BeGreaterThan()`), consider adding the **FluentAssertions** NuGet package.
